def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        usage_ratio = item / capacity
        priority = 0.0
        if usage_ratio > 1.5:
            priority += 2000 * usage_ratio
            if usage_ratio > 2:
                priority += 500
            else:
                priority += 300 * (usage_ratio - 1.5)
        elif usage_ratio > 1:
            priority += 1500 * (usage_ratio - 1)
        elif usage_ratio == 1:
            priority += 200
        else:
            try:
                log_val = np.log(1 - usage_ratio + 1e-12)
            except FloatingPointError:
                log_val = -np.inf
            if log_val < -2:
                priority += -log_val * 10
            elif log_val < -1:
                priority += -log_val * 6
            else:
                priority += -log_val * 2
            extra_factor = 0
            for j in range(1, 6):
                power = usage_ratio ** j
                if power < 0.3:
                    extra_factor += power * 12 / j
                elif power < 0.7:
                    extra_factor += (1 - power) * 8 / (j + 1)
                else:
                    extra_factor -= power * 5 / (j + 2)
            priority += extra_factor
        if capacity < 0.02:
            priority += 90
            if usage_ratio > 0.8:
                priority += 40
                if usage_ratio > 0.95:
                    priority += 20
        elif capacity < 0.3:
            priority += 35
            if usage_ratio > 0.85:
                priority += 25
            elif usage_ratio < 0.25:
                priority -= 10
        elif capacity < 1:
            priority += 10
            if usage_ratio < 0.4:
                priority -= 8
            elif usage_ratio > 0.85:
                priority += 30
        else:
            if usage_ratio < 0.2:
                priority -= 10
            elif usage_ratio > 0.9:
                priority += 40
        proximity_score = 0
        if capacity % 2 == 0:
            proximity_score += 5
            if capacity % 4 == 0:
                proximity_score += 3
        if int(capacity * 100) % 5 == 0:
            proximity_score -= 4
        for k in range(1, 5):
            target = k / 6
            diff = abs(usage_ratio - target)
            if diff < 0.08:
                proximity_score += 12 / k
            elif diff < 0.15:
                proximity_score += 5 / k
            else:
                proximity_score -= diff * 3 / (k + 1)
        adjustment = 0
        thresholds = [0.1, 0.25, 0.5, 0.75, 0.9]
        weights = [5, -3, 4, -2, 6]
        for thr, w in zip(thresholds, weights):
            if abs(usage_ratio - thr) < 0.05:
                adjustment += w * (1 - abs(usage_ratio - thr)*20)
            elif usage_ratio > thr:
                adjustment += w / (thr * 10 + 1)
        priority += proximity_score + adjustment
        if priority < 0:
            priority = 0
        priorities[i] = priority
    return priorities
